#!/usr/bin/env python3 """flow_metrics.py — Lead Time, Cycle Time, Throughput from transitions.csv""" from __future__ import annotations import sys import pandas as pd
def main(path: str) -> int: df = pd.read_csv(path, parse_dates=["ts"]) # transitions: issue_id, status, ts pivot = df.pivot_table(index="issue_id", columns="status", values="ts", aggfunc="min") if not {"To Do", "In Progress", "Done"}.issubset(pivot.columns): print("Missing required statuses", file=sys.stderr) return 2 pivot["lead_time_days"] = (pivot["Done"] - pivot["To Do"]).dt.total_seconds() / 86400 pivot["cycle_time_days"] = (pivot["Done"] - pivot["In Progress"]).dt.total_seconds() / 86400 summary = pivot[["lead_time_days", "cycle_time_days"]].dropna().describe(percentiles=[.5, .85, .95]) print(summary.to_string()) # throughput per ISO week weekly = df[df.status == "Done"].set_index("ts").resample("W").issue_id.nunique() print("\nWeekly throughput:") print(weekly.to_string()) return 0
if __name__ == "__main__": sys.exit(main(sys.argv[1]))
